// 主题选择器
import ParamCard from "./Tools/ParamCard";
import ParamHeader from "./Tools/ParamHeader";

function ThemeSelector({
    name,
    value = 'pink',
    onChange,
    iconName = 'Moon',
    colorIndex = 9,
    onIconClick
}) {
    const themes = [
        { value: 'pink', gradient: 'from-pink-300 to-purple-300', ring: 'ring-pink-400' },
        { value: 'blue', gradient: 'from-blue-300 to-cyan-300', ring: 'ring-blue-400' },
        { value: 'peach', gradient: 'from-orange-300 to-pink-300', ring: 'ring-orange-400' }
    ];

    return (
        <ParamCard>
            <div className="flex items-center gap-2 mb-3">
                <ParamHeader
                    label={name}
                    iconName={iconName}
                    colorIndex={colorIndex}
                    onIconClick={onIconClick}
                />
            </div>
            <div className="flex gap-2">
                {themes.map((theme) => (
                    <button
                        key={theme.value}
                        onClick={() => onChange(theme.value)}
                        className={`flex-1 h-10 rounded-xl bg-gradient-to-r ${theme.gradient} transition-all ${
                            value === theme.value ? `ring-4 ${theme.ring} scale-105 shadow-lg` : 'hover:scale-105'
                        }`}
                    />
                ))}
            </div>
        </ParamCard>
    );
}

export default ThemeSelector
